parameters.jsCode:
let score = 0;

if ($json.billing_shipping_mismatch) score += 2;
if ($json.high_value_order) score += 3;
if ($json.suspicious_email) score += 1;

// reduce risk if order created by admin
if ($json.created_via === 'admin') score -= 2;

// never allow negative score
if (score < 0) score = 0;

return [{
  json: {
    ...$json,
    fraud_score: score
  }
}];

